import{c as e,Q as r,j as o,m as a}from"./chunks/framework.cL5ZtNug.js";const f=JSON.parse('{"title":"Phoenix Tuner","description":"","frontmatter":{},"headers":[],"relativePath":"tooling/phoenix-tuner.md","filePath":"tooling/phoenix-tuner.md"}'),n={name:"tooling/phoenix-tuner.md"};function i(d,t,s,l,h,u){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="phoenix-tuner" tabindex="-1">Phoenix Tuner <a class="header-anchor" href="#phoenix-tuner" aria-label="Permalink to &quot;Phoenix Tuner&quot;">​</a></h1><p>Configure CTRE devices (TalonFX, CANcoder, Pigeon).</p><h2 id="what-is-phoenix-tuner" tabindex="-1">What Is Phoenix Tuner? <a class="header-anchor" href="#what-is-phoenix-tuner" aria-label="Permalink to &quot;What Is Phoenix Tuner?&quot;">​</a></h2><p>Phoenix Tuner is CTRE&#39;s tool for configuring and diagnosing their devices. It connects to devices on the CAN bus.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Download from the <a href="https://store.ctr-electronics.com/software/" target="_blank" rel="noreferrer">CTRE website</a>. Available for Windows, macOS, and Linux.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Device Discovery</strong></td><td>Find all CTRE devices on the CAN bus</td></tr><tr><td><strong>Firmware Update</strong></td><td>Update device firmware to the latest version</td></tr><tr><td><strong>Self Test</strong></td><td>Verify device health and connectivity</td></tr><tr><td><strong>Tune PID</strong></td><td>Tune onboard PID gains in real-time</td></tr><tr><td><strong>Configure Limits</strong></td><td>Set soft/hard forward and reverse limits</td></tr><tr><td><strong>Signal Logging</strong></td><td>Record sensor data for analysis</td></tr></tbody></table><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><ol><li>Connect to the robot network (USB or WiFi)</li><li>Open Phoenix Tuner</li><li>Select the device on the CAN bus</li><li>Configure parameters (PID, limits, current limits)</li><li><strong>Save to device flash</strong> (persists without code)</li></ol><h2 id="when-to-use-phoenix-tuner" tabindex="-1">When to Use Phoenix Tuner <a class="header-anchor" href="#when-to-use-phoenix-tuner" aria-label="Permalink to &quot;When to Use Phoenix Tuner&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Task</th><th>Use Phoenix Tuner?</th></tr></thead><tbody><tr><td>Set CAN ID</td><td>Yes (or use code)</td></tr><tr><td>Update firmware</td><td>Yes</td></tr><tr><td>Tune onboard PID</td><td>Yes (faster than code iteration)</td></tr><tr><td>Set current limits</td><td>Yes</td></tr><tr><td>Check device health</td><td>Yes</td></tr><tr><td>Configure swerve offsets</td><td>Yes (CANCoder)</td></tr></tbody></table><h2 id="swerve-module-setup" tabindex="-1">Swerve Module Setup <a class="header-anchor" href="#swerve-module-setup" aria-label="Permalink to &quot;Swerve Module Setup&quot;">​</a></h2><p>For each swerve module:</p><ol><li>Find the CANcoder in Phoenix Tuner</li><li>Rotate the wheel to a known angle (pointing forward)</li><li>Set the <strong>absolute sensor offset</strong> to zero</li><li>Save to flash</li></ol><p>This ensures all modules start at a known orientation.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Fix</th></tr></thead><tbody><tr><td>Device not found</td><td>Check CAN wiring, verify CAN ID</td></tr><tr><td>Firmware update fails</td><td>Power cycle the device, retry</td></tr><tr><td>PID tuning not working</td><td>Verify motor is connected and enabled</td></tr></tbody></table>',18)])])}const b=e(n,[["render",i]]);export{f as __pageData,b as default};
